import * as React from 'react';
import Avatar from '@mui/material/Avatar';
import AvatarGroup from '@mui/material/AvatarGroup';
import Box from '@mui/material/Box';
import Card from '@mui/material/Card';
import CardContent from '@mui/material/CardContent';
import CardMedia from '@mui/material/CardMedia';
import Chip from '@mui/material/Chip';
import Grid from '@mui/material/Grid2';
import IconButton from '@mui/material/IconButton';
import Typography from '@mui/material/Typography';
import { styled } from '@mui/material/styles';
import SearchRoundedIcon from '@mui/icons-material/SearchRounded';
import RssFeedRoundedIcon from '@mui/icons-material/RssFeedRounded';
import { OutlinedInput, InputAdornment } from '@mui/material';
const cardData = {
  All: [
    {
      img: 'https://picsum.photos/800/450?random=1',
      tag: 'WEB APPS',
      title: 'Revolutionizing software development with cutting-edge tools',
      description:
        'Our latest engineering tools are designed to streamline workflows and boost productivity.',
      authors: [
        { name: 'Remy Sharp', avatar: '/static/images/avatar/1.jpg' },
        { name: 'Travis Howard', avatar: '/static/images/avatar/2.jpg' },
      ],
    },
    {
      img: 'https://picsum.photos/800/450?random=2',
      tag: 'ANDROID APPS',
      title: 'Innovative product features that drive success',
      description:
        'Explore the key features of our latest product release that are helping businesses achieve their goals.',
      authors: [{ name: 'Erica Johns', avatar: '/static/images/avatar/6.jpg' }],
    },
    // Add more dummy projects across categories
  ],
  'WEB APPS': [
    {
      img: 'https://picsum.photos/800/450?random=3',
      tag: 'WEB APPS',
      title: 'Building fast and scalable web applications',
      description:
        'Our framework is designed to help developers build scalable and performant web applications.',
      authors: [{ name: 'John Doe', avatar: '/static/images/avatar/4.jpg' }],
    },
    // Add more "WEB APPS" specific projects here
  ],
  'ANDROID APPS': [
    {
      img: 'https://picsum.photos/800/450?random=4',
      tag: 'ANDROID APPS',
      title: 'Building intuitive Android apps',
      description:
        'We specialize in creating user-friendly Android apps with a focus on seamless performance.',
      authors: [{ name: 'Jane Doe', avatar: '/static/images/avatar/5.jpg' }],
    },
    // Add more "ANDROID APPS" specific projects here
  ],
  // More categories can be added as needed
};

const SyledCard = styled(Card)(({ theme }) => ({
  display: 'flex',
  flexDirection: 'column',
  padding: 0,
  height: '100%',
  backgroundColor: (theme.vars || theme).palette.background.paper,
  '&:hover': {
    backgroundColor: 'transparent',
    cursor: 'pointer',
  },
  '&:focus-visible': {
    outline: '3px solid',
    outlineColor: 'hsla(210, 98%, 48%, 0.5)',
    outlineOffset: '2px',
  },
}));

const SyledCardContent = styled(CardContent)({
  display: 'flex',
  flexDirection: 'column',
  gap: 4,
  padding: 16,
  flexGrow: 1,
  '&:last-child': {
    paddingBottom: 16,
  },
});

const StyledTypography = styled(Typography)({
  display: '-webkit-box',
  WebkitBoxOrient: 'vertical',
  WebkitLineClamp: 2,
  overflow: 'hidden',
  textOverflow: 'ellipsis',
});

function Author({ authors }) {
  return (
    <Box
      sx={{
        display: 'flex',
        flexDirection: 'row',
        gap: 2,
        alignItems: 'center',
        justifyContent: 'space-between',
        padding: '16px',
      }}
    >
      <Box
        sx={{ display: 'flex', flexDirection: 'row', gap: 1, alignItems: 'center' }}
      >
        <AvatarGroup max={3}>
          {authors.map((author, index) => (
            <Avatar
              key={index}
              alt={author.name}
              src={author.avatar}
              sx={{ width: 24, height: 24 }}
            />
          ))}
        </AvatarGroup>
        <Typography variant="caption">
          {authors.map((author) => author.name).join(', ')}
        </Typography>
      </Box>
      <Typography variant="caption">July 14, 2021</Typography>
    </Box>
  );
}

export function Search() {
  return (
    <Box sx={{ width: { xs: '100%', md: '25ch' } }} variant="outlined">
      <OutlinedInput
        size="small"
        id="search"
        placeholder="Search…"
        sx={{ flexGrow: 1 }}
        startAdornment={
          <InputAdornment position="start" sx={{ color: 'text.primary' }}>
            <SearchRoundedIcon fontSize="small" />
          </InputAdornment>
        }
        inputProps={{
          'aria-label': 'search',
        }}
      />
    </Box>
  );
}

export default function Projects() {
  const [selectedCategory, setSelectedCategory] = React.useState('All');

  const handleCategoryClick = (category) => {
    setSelectedCategory(category);
  };

  return (
    <Box sx={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
      <div>
        <Typography variant="h5" gutterBottom>
          Projects
        </Typography>
        <Typography>Stay in the loop with the latest about our products</Typography>
      </div>
      <Box
        sx={{
          display: { xs: 'flex', sm: 'none' },
          flexDirection: 'row',
          gap: 1,
          width: { xs: '100%', md: 'fit-content' },
          overflow: 'auto',
        }}
      >
        <Search />
        <IconButton size="small" aria-label="RSS feed">
          <RssFeedRoundedIcon />
        </IconButton>
      </Box>
      <Box
        sx={{
          display: 'flex',
          flexDirection: { xs: 'column-reverse', md: 'row' },
          width: '100%',
          justifyContent: 'space-between',
          alignItems: { xs: 'start', md: 'center' },
          gap: 4,
          overflow: 'auto',
        }}
      >
        <Box
          sx={{
            display: 'inline-flex',
            flexDirection: 'row',
            gap: 3,
            overflow: 'auto',
          }}
        >
          {Object.keys(cardData).map((category) => (
            <Chip
              key={category}
              onClick={() => handleCategoryClick(category)}
              size="medium"
              label={category}
              sx={{
                backgroundColor: selectedCategory === category ? 'primary.main' : 'white',
                color: selectedCategory === category ? 'white' : 'text.primary',
                cursor: 'pointer',
              }}
            />
          ))}
        </Box>
        <Box
          sx={{
            display: { xs: 'none', sm: 'flex' },
            flexDirection: 'row',
            gap: 1,
            alignItems: 'center',
            justifyContent: 'flex-end',
            width: 'fit-content',
            overflow: 'auto',
          }}
        >
          <Search />
          <IconButton size="small" aria-label="RSS feed">
            <RssFeedRoundedIcon />
          </IconButton>
        </Box>
      </Box>
      <Grid container spacing={3}>
        {cardData[selectedCategory].map((card, index) => (
          <Grid
            key={index}
            xs={12} sm={6} md={4}
            item
            sx={{
              display: 'flex',
              flexDirection: 'column',
              gap: 1,
              padding: 1,
            }}
          >
            <SyledCard variant="outlined">
              <CardMedia
                component="img"
                height="140"
                image={card.img}
                alt="Card Image"
              />
              <SyledCardContent>
                <Chip size="small" label={card.tag} color="primary" />
                <StyledTypography variant="h6" component="h2">
                  {card.title}
                </StyledTypography>
                <Typography variant="body2">{card.description}</Typography>
                <Author authors={card.authors} />
              </SyledCardContent>
            </SyledCard>
          </Grid>
        ))}
      </Grid>
    </Box>
  );
}
